package main

import (
    "crypto/rand"
    "encoding/base64"
    "golang.org/x/crypto/bcrypt"
    "golang.org/x/crypto/scrypt"
)

// Compliant: Using bcrypt (recommended)
type SecureUser struct {
    Username     string
    PasswordHash string // Store hash, never plaintext
}

func hashPasswordBcrypt(password string) (string, error) {
    // bcrypt automatically handles salt generation and is designed for passwords
    hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
    if err != nil {
        return "", err
    }
    return string(hash), nil
}

func verifyPasswordBcrypt(password, hash string) bool {
    err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
    return err == nil
}

// Compliant: Using scrypt (alternative)
func hashPasswordScrypt(password string) (string, error) {
    // Generate random salt
    salt := make([]byte, 16)
    _, err := rand.Read(salt)
    if err != nil {
        return "", err
    }

    // Generate hash using scrypt
    hash, err := scrypt.Key([]byte(password), salt, 32768, 8, 1, 32)
    if err != nil {
        return "", err
    }

    // Combine salt and hash for storage
    combined := append(salt, hash...)
    return base64.StdEncoding.EncodeToString(combined), nil
}

func verifyPasswordScrypt(password, storedHash string) bool {
    decoded, err := base64.StdEncoding.DecodeString(storedHash)
    if err != nil || len(decoded) < 48 { // 16 byte salt + 32 byte hash
        return false
    }

    salt := decoded[:16]
    hash := decoded[16:]

    testHash, err := scrypt.Key([]byte(password), salt, 32768, 8, 1, 32)
    if err != nil {
        return false
    }

    // Compare hashes
    if len(testHash) != len(hash) {
        return false
    }

    for i := range hash {
        if hash[i] != testHash[i] {
            return false
        }
    }
    return true
}

// Compliant: Complete user management example
func createSecureUser(username, password string) (*SecureUser, error) {
    hashedPassword, err := hashPasswordBcrypt(password)
    if err != nil {
        return nil, err
    }

    return &SecureUser{
        Username:     username,
        PasswordHash: hashedPassword,
    }, nil
}

func authenticateUser(user *SecureUser, password string) bool {
    return verifyPasswordBcrypt(password, user.PasswordHash)
}
